import{_ as e,o as a,c as i,a0 as o}from"./chunks/framework.jwovEGr5.js";const d=JSON.parse('{"title":"Sanctuary Battle","description":"","frontmatter":{},"headers":[],"relativePath":"events/sanctuary-battle.md","filePath":"events/sanctuary-battle.md"}'),l={name:"events/sanctuary-battle.md"};function r(n,t,s,c,h,u){return a(),i("div",null,[...t[0]||(t[0]=[o('<h1 id="sanctuary-battle" tabindex="-1">Sanctuary Battle <a class="header-anchor" href="#sanctuary-battle" aria-label="Permalink to &quot;Sanctuary Battle&quot;">​</a></h1><p>Sanctuary Battle is the default template for an alliance <strong>PvP control and occupation</strong> event.</p><blockquote><p>Screenshot placeholder: event-sanctuary.png</p></blockquote><blockquote><p>Warning: Do not treat Sanctuary Battle like Bear Trap. This default is <strong>not</strong> mainly a score race. Participation and control outcome matter first. Score is optional and off by default.</p></blockquote><h2 id="what-this-event-is-for" tabindex="-1">What this event is for <a class="header-anchor" href="#what-this-event-is-for" aria-label="Permalink to &quot;What this event is for&quot;">​</a></h2><p>This template is meant for tracking things like:</p><ul><li>who participated</li><li>whether your alliance won or held control</li><li>reward eligibility tied to attendance or outcome</li><li>optional player-level score only when a useful screenshot actually includes one</li></ul><h2 id="how-this-default-is-set-up" tabindex="-1">How this default is set up <a class="header-anchor" href="#how-this-default-is-set-up" aria-label="Permalink to &quot;How this default is set up&quot;">​</a></h2><ul><li>event style: single-session</li><li>main tracking style: participation-focused</li><li>score required: no</li><li>score support: optional</li><li>position required: no</li></ul><p>The goal is to support a PvP control event without forcing fake score data into it.</p><h2 id="what-to-import" tabindex="-1">What to import <a class="header-anchor" href="#what-to-import" aria-label="Permalink to &quot;What to import&quot;">​</a></h2><p>Import whatever evidence best matches how your kingdom tracks the event:</p><ul><li>participation lists</li><li>outcome notes</li><li>optional player score or combat values, if your screenshot includes them</li></ul><p>If you do not have meaningful personal score data, that is fine. You can still track participation correctly.</p><h2 id="what-is-visible-in-the-interface-today" tabindex="-1">What is visible in the interface today <a class="header-anchor" href="#what-is-visible-in-the-interface-today" aria-label="Permalink to &quot;What is visible in the interface today&quot;">​</a></h2><p>The current event settings interface clearly supports the participation-focused setup and optional score behavior.</p><p>The Sanctuary Battle control-event metadata is now also preserved correctly when this template is saved, customized, or accepted through a proposal. The settings page shows that this is a control-focused event and lists the supported control-style capabilities as read-only guidance.</p><p>Some deeper control-specific fields still are <strong>not yet editable as separate form controls</strong>. So user-facing setup today should focus on:</p><ul><li>participation</li><li>optional score</li><li>visibility and reward behavior</li></ul><h2 id="good-practice" tabindex="-1">Good practice <a class="header-anchor" href="#good-practice" aria-label="Permalink to &quot;Good practice&quot;">​</a></h2><ul><li>decide first whether you are tracking attendance, outcome, or both</li><li>only use score if the screenshot really gives a useful player-level number</li><li>explain your local reward rule clearly so reviewers know what &quot;good&quot; looks like for this event</li></ul><h2 id="protection-note" tabindex="-1">Protection note <a class="header-anchor" href="#protection-note" aria-label="Permalink to &quot;Protection note&quot;">​</a></h2><p>This is a default template, so it is <strong>editable but not deletable</strong>. See <a href="./../roles/protection-rules.html">Safety Rules You&#39;ll Run Into</a>.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./default-events.html">The Default Events</a></li><li><a href="./../how-to/event-settings.html">Configure Event Settings</a></li><li><a href="./../reference/participant-eligibility.html">Participant Eligibility Statuses</a></li></ul>',25)])])}const f=e(l,[["render",r]]);export{d as __pageData,f as default};
